const RUBLE_EXCHANGE_RATE = 79;
const billing_polza = Number($json.billing_polza) - Number($json.amount);
const billing_neuro = -(Number($json.billing_neuro) - Number($json.total_usage)) / 100;
const diff = DateTime.fromISO($json.created_at).diff(DateTime.fromISO($json.finished_at)).negate().toFormat("hh':'mm':'ss");
const avv_time = DateTime.fromISO($json.created_at).diff(DateTime.fromISO($json.finished_at)).negate().toMillis() / (Number($json.chunks_total) || 1) / 1000;
const avv_cost = (billing_polza + billing_neuro * RUBLE_EXCHANGE_RATE) / (Number($json.chunks_total) || 1);

return {
  message: `
✅ <b>Перевод завершен!</b>

📄 Документ (исходный): ${$json.file_name}
📄 Документ (с переводом): ${$json.translated_file}

💰 Итоговая стоимость Polza.ai: ₽${billing_polza.toFixed(2)}
💰 Итоговая стоимость NeuroAPI: $${billing_neuro.toFixed(2)} (₽${(billing_neuro * RUBLE_EXCHANGE_RATE).toFixed(2).toString().replace(/\B(?=(\d{3})+(?!\d))/g, " ")})

🗓 Старт: <code>${DateTime.fromISO($json.created_at).toFormat("dd.MM.yyyy HH:mm:ss")}</code>
⏱ Переведено за: <code>${diff} (чч:мм:сс)</code>

🔢 <b>Чанков переведено: ${$json.chunks_total}</b>
⌛ Среднее время перевода 1 чанка: ${(avv_time).toLocaleString()} сек.
💰 Средняя стоимость 1 чанка ≈ ₽${avv_cost.toFixed(2)}

<i>Сообщение сгенерировано автоматически.</i>`,
  type: 'finish',
  button: {}
};
